const body = $input.item.json.body || {};
const formType = String(body.form_type || '').toLowerCase().trim();
const allowed = ['advisor', 'carrier'];
if (allowed.indexOf(formType) === -1) {
  return { json: { ok: false, status: 400, error: 'form_type must be "advisor" or "carrier"' } };
}

const email = String(body.email || '').trim().toLowerCase();
const emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!email || !emailRe.test(email)) {
  return { json: { ok: false, status: 400, error: 'Valid email required' } };
}
const fullName = String(body.full_name || '').trim().slice(0, 200);
if (!fullName) return { json: { ok: false, status: 400, error: 'full_name required' } };

// Per form_type, gather the fields. Anything not in the small allowed
// set goes into the notes JSON (cap at 2KB so a bot can't fill the
// row with noise).
function safeStr(v, max) { return (v == null ? '' : String(v)).trim().slice(0, max || 200); }

const extras = {};
if (formType === 'advisor') {
  extras.ribo_status        = safeStr(body.ribo_status,    80);
  extras.years_licensed     = safeStr(body.years_licensed, 80);
  extras.current_carriers   = safeStr(body.current_carriers, 500);
  extras.book_size          = safeStr(body.book_size,      80);
  extras.specialties        = safeStr(body.specialties,    500);
  extras.why_crystallux     = safeStr(body.why_crystallux, 1000);
} else {
  extras.product_lines      = safeStr(body.product_lines,  500);
  extras.target_markets     = safeStr(body.target_markets, 300);
  extras.distribution_today = safeStr(body.distribution_today, 500);
  extras.partnership_goal   = safeStr(body.partnership_goal, 1000);
}
const notesStr = 'Application via ' + (body.form_source || 'web') + ':\n' +
  Object.keys(extras).filter(function (k) { return extras[k]; })
        .map(function (k) { return k + ': ' + extras[k]; })
        .join('\n');

const leadRow = {
  full_name:         fullName,
  email:             email,
  phone:             safeStr(body.phone, 40),
  company:           safeStr(body.company, 200) || (formType === 'advisor' ? 'Independent advisor' : 'Insurance carrier'),
  job_title:         formType === 'advisor' ? 'Insurance Advisor' : 'Carrier rep',
  industry:          'insurance',
  city:              safeStr(body.city, 120),
  source:            formType === 'advisor' ? 'advisor_application' : 'carrier_inquiry',
  lead_status:       'New Lead',
  product_type:      'insurance',
  lead_type:         formType === 'advisor' ? 'advisor_candidate' : 'carrier_prospect',
  do_not_contact:    false,
  unsubscribed:      false,
  total_emails_sent: 0,
  lead_score:        70,            // applications come in warm by default
  notes:             notesStr.slice(0, 2000),
  updated_at:        new Date().toISOString()
};

return { json: {
  form_type:    formType,
  email:        email,
  full_name:    fullName,
  lead_row:     leadRow,
  notify_subject: formType === 'advisor'
    ? '[Crystallux] New advisor application: ' + fullName
    : '[Crystallux] New carrier inquiry: ' + (leadRow.company || fullName),
  notify_body:    notesStr,
  extras:       extras
} };

// Build the Postmark notification email to Mary.
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};
const rows = allOf('Insert Lead');
const v = $('Validate + Build').item.json;
const leadId = rows.length > 0 ? rows[0].id : null;

const esc = function (s) { return String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;'); };
const extrasHtml = Object.keys(v.extras || {})
  .filter(function (k) { return v.extras[k]; })
  .map(function (k) { return '<tr><td style="padding:4px 12px 4px 0;color:#6b7280;text-transform:capitalize">' + esc(k.replace(/_/g, ' ')) + '</td><td style="padding:4px 0">' + esc(v.extras[k]) + '</td></tr>'; })
  .join('');

const html =
  '<div style="font-family:Arial,Helvetica,sans-serif;font-size:14px;line-height:1.55;color:#333;max-width:640px">' +
  '<p>New ' + (v.form_type === 'advisor' ? 'advisor application' : 'carrier inquiry') + ' just arrived.</p>' +
  '<table style="border-collapse:collapse;margin:14px 0;font-size:13px">' +
    '<tr><td style="padding:4px 12px 4px 0;color:#6b7280">Name</td><td style="padding:4px 0"><strong>' + esc(v.full_name) + '</strong></td></tr>' +
    '<tr><td style="padding:4px 12px 4px 0;color:#6b7280">Email</td><td style="padding:4px 0"><a href="mailto:' + esc(v.email) + '">' + esc(v.email) + '</a></td></tr>' +
    extrasHtml +
  '</table>' +
  (leadId ? '<p><a href="https://admin.crystallux.org/pages/leads.html?lead_id=' + esc(leadId) + '" style="display:inline-block;padding:9px 16px;background:#7C3AED;color:#fff;border-radius:6px;text-decoration:none;font-weight:600">Open in admin →</a></p>' : '<p style="color:#dc2626">(Lead insert returned no row — check Supabase RLS / service role)</p>') +
  '<p style="color:#6b7280;font-size:11px;margin-top:18px">Lead ID: ' + esc(leadId || '(none)') + '</p>' +
  '</div>';

return { json: {
  ok: !!leadId,
  lead_id: leadId,
  form_type: v.form_type,
  postmark_body: {
    From:    'info@crystallux.org',
    To:      'info@crystallux.org',
    Subject: v.notify_subject,
    HtmlBody: html,
    TextBody: 'New ' + v.form_type + ' application: ' + v.full_name + ' <' + v.email + '>\n\n' + v.notify_body,
    MessageStream: 'outbound',
    Tag: 'mga-application',
    Metadata: { lead_id: leadId || '', form_type: v.form_type }
  }
} };

const postmark = $input.item.json;
const v = $('Build Notification').first().json;
const sentOk = !!(postmark && postmark.MessageID);
return { json: {
  ok: v.ok,
  lead_id: v.lead_id,
  form_type: v.form_type,
  notification_sent: sentOk,
  message: v.form_type === 'advisor'
    ? 'Thanks — your advisor application is in. Mary will reply from info@crystallux.org within 24 hours.'
    : 'Thanks — your carrier inquiry is in. Mary will reach out from info@crystallux.org within 24 hours.'
} };
